using UnityEngine; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.Save { public class SparkleRewardBinder:MonoBehaviour { [SerializeField] SaveManager saveManager; [SerializeField] GoalManager goalManager; [SerializeField] StageManager stageManager; bool done; void Awake(){ saveManager??=FindAnyObjectByType<SaveManager>(); goalManager??=FindAnyObjectByType<GoalManager>(); stageManager??=FindAnyObjectByType<StageManager>(); } void OnEnable(){ if(goalManager!=null) goalManager.OnStageCleared+=Handle; } void OnDisable(){ if(goalManager!=null) goalManager.OnStageCleared-=Handle; } public void ResetRewardFlag()=>done=false; void Handle(){ if(done||saveManager==null||stageManager?.CurrentStage==null) return; int amount=stageManager.CurrentStage.RewardSparklePieces; if(amount>0) saveManager.AddSparklePiecesAndSave(amount); done=true; } } }
